class ezAlert{constructor(className){this.className=className}
initAlert(target,content,dismissible='button',allowSpec=!0,extraClasses='',closeClass=''){if(!this.isElement(target)){if(typeof(target)=='string'){target=document.getElementById(target)}}
if(typeof(extraClasses)!='string')
extraClasses='';if(dismissible!=='button'&&dismissible!=='click'){if(dismissible)dismissible='button'}
if(!allowSpec){let regex=/\w| |\.|\,|\!|\?|\"'/g;let found=content.match(regex);if(found.length<content.length){console.log('Alert content may not have any characters that do not match ',regex);return!1}}
if(target===undefined||target===null){console.log('Invalid element to create alert at!');return!1}
let alert;(dismissible=='click')?alert=document.createElement("a"):alert=document.createElement("div");alert.className=this.className+" "+extraClasses;alert.innerHTML=content;if(dismissible=='click'){alert.href='#';alert.style.display='block';alert.style.textDecoration='none';alert.addEventListener('click',e=>{e.target.parentNode.removeChild(e.target)})}
if(dismissible=='button'){let alertClose=document.createElement("a");alertClose.innerHTML='X';alertClose.href='#';(closeClass=='')?alertClose.className='close':alertClose.className=closeClass;alertClose.style.textDecoration='none';alertClose.style.position='relative';alertClose.style.float='right';alertClose.style.padding='0px 10px 0px 0px';alertClose.style.fontWeight='800';alert.appendChild(alertClose);alertClose.addEventListener('click',e=>{e.target.parentNode.parentNode.removeChild(e.target.parentNode)})}
target.prepend(alert)};isElement(obj){try{return obj instanceof HTMLElement}catch(e){return(typeof obj==="object")&&(obj.nodeType===1)&&(typeof obj.style==="object")&&(typeof obj.ownerDocument==="object")}}}